  ('d3s5', null, null, 'Fireside Chat and Guided Reflection with CEO Dr. Clarisse Mendoza-Davis', 'fireside-chat-guided-reflection-dr-clarisse-mendoza-davis', 'fireside_chat', '2026-04-03', '2026-04-03T11:10:00-04:00', '2026-04-03T12:15:00-04:00', 'Maya Angelou Learning Campus, P.A.C., Cafeteria, & Gymnasium', 'Performing Arts Center', 'A combined fireside chat and guided reflection led by CEO Dr. Clarisse Mendoza-Davis to formally close the convening.', 'CEO Dr. Clarisse Mendoza-Davis will lead a combined fireside chat and guided reflection to formally close the convening, bringing the conversation back to the partnership, leadership, and accountability themes that shaped the week.', null, 'scheduled', true, true, false),
  ('d3s6', null, null, 'Community Lunch', 'community-lunch', 'lunch', '2026-04-03', '2026-04-03T12:15:00-04:00', '2026-04-03T13:15:00-04:00', 'Maya Angelou Learning Campus, P.A.C., Cafeteria, & Gymnasium', 'Cafeteria', 'Shared lunch for attendees following the convening close.', 'Lunch will be served following the closing fireside chat and guided reflection.', null, 'scheduled', true, false, false),
